code.C:
#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);
    int v1[32]; // Array to store binary digits
    int idx = 0;

    // Converting decimal to binary representation
    while (n != 0) {
        v1[idx++] = n % 2;
        n /= 2;
    }

    // Printing the binary in reverse order
    for (int i = idx - 1; i >= 0; i--) {
        printf("%d", v1[i]);
    }
    printf("\n");

    return 0;
}

