const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

rl.on('line', (line) => {
    let n = Number(line.trim());
    const v1 = [];

    // Converting decimal to binary representation
    while (n !== 0) {
        v1.push(n % 2);
        n = Math.floor(n / 2);
    }

    // Printing the binary in reverse order
    console.log(v1.reverse().join(''));
    rl.close();
});
